    'seo_title' => 'Wedding & Prom Car Hire York, Yorkshire',
    'seo_desc'  => 'Luxury wedding car hire and prom limo hire in York, Yorkshire. Rolls Royce Phantom, stretch limos and more. 5-star rated. Price-match guarantee. Book today.',
  ],
];

$template = 'page-templates/template-location-page.php';
$created  = 0;
$skipped  = 0;

foreach ( $pages as $p ) {

    // Skip if slug already exists
    if ( get_page_by_path( $p['slug'], OBJECT, 'page' ) ) {
        echo "SKIP  : {$p['slug']}\n";
        $skipped++;
        continue;
    }

    $post_id = wp_insert_post( [
        'post_title'   => $p['title'],
        'post_name'    => $p['slug'],
        'post_status'  => 'publish',
        'post_type'    => 'page',
        'post_content' => '',
    ], true );

    if ( is_wp_error( $post_id ) ) {
        echo "ERROR : {$p['slug']} — " . $post_id->get_error_message() . "\n";
        continue;
    }

    // Page template
    update_post_meta( $post_id, '_wp_page_template', $template );

    // ACF fields
    update_post_meta( $post_id, 'lp_location_name', $p['location'] );
    update_post_meta( $post_id, 'lp_county',         $p['county']   );
    update_post_meta( $post_id, 'lp_hero_tagline',   $p['tagline']  );
    update_post_meta( $post_id, 'lp_intro_text',     $p['intro']    );
    update_post_meta( $post_id, 'lp_nearby_towns',   $p['nearby']   );

    // Yoast SEO
    update_post_meta( $post_id, '_yoast_wpseo_focuskw',  $p['seo_kw']    );
    update_post_meta( $post_id, '_yoast_wpseo_title',    $p['seo_title'] );
    update_post_meta( $post_id, '_yoast_wpseo_metadesc', $p['seo_desc']  );

    echo "CREATED: {$p['slug']} (ID: {$post_id})\n";
    $created++;
}

echo "\nDone. Created: {$created} | Skipped: {$skipped}\n";
